+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { getStore, hasTrait } from '../../trait/trait';
+import type { Trait } from '../../trait/types';
+import type { PredicateModifier, QueryInstance } from '../types';
+import type { World } from '../../world';
+
+export function matchesPredicate(
+    world: World,
+    entity: Entity,
+    predicate: PredicateModifier
+): boolean {
+    const data: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        data.push(trait[$internal].get(getEntityId(entity), getStore(world, trait)));
+    }
+    return predicate.predicate(data as never);
+}
+
+export function checkPredicates(world: World, query: QueryInstance, entity: Entity): boolean {
+    for (const predicate of query.predicates) {
+        if (!matchesPredicate(world, entity, predicate)) return false;
+    }
+    for (const predicate of query.notPredicates) {
+        if (matchesPredicate(world, entity, predicate)) return false;
+    }
+    if (query.orPredicates.length > 0) {
+        let match = false;
+        for (const predicate of query.orPredicates) {
+            if (matchesPredicate(world, entity, predicate)) {
+                match = true;
+                break;
+            }
+        }
+        if (!match) return false;
+    }
+    return true;
+}
+
+export function updatePredicateQueries(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+    const queries = new Set([...instance.queries, ...instance.trackingQueries]);
+    for (const query of queries) {
+        if (
+            query.predicates.length === 0 &&
+            query.notPredicates.length === 0 &&
+            query.orPredicates.length === 0 &&
+            query.predicateTracking.length === 0
+        )
+            continue;
+
+        if (query.predicateTracking.length > 0) {
+            let eventMatch = false;
+            for (const tracking of query.predicateTracking) {
+                const states = query.predicateStates.get(tracking.predicate)!;
+                const previous = states.get(entity) ?? false;
+                const current = matchesPredicate(world, entity, tracking.predicate);
+                states.set(entity, current);
+                eventMatch ||= 
+                    (tracking.type === 'add' && !previous && current) ||
+                    (tracking.type === 'remove' && previous && !current) ||
+                    (tracking.type === 'change' && previous !== current);
+            }
+            if (eventMatch && query.check(world, entity)) query.add(entity);
+            continue;
+        }
+
+        if (query.check(world, entity)) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
